import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is the least common multiple?", a: "The least common multiple is the smallest positive number that is a multiple of every number in a set. For example, the LCM of 4 and 6 is 12." },
  { q: "How do you find the LCM using prime factorization?", a: "Prime factor each number, then take every prime factor at its highest power across all numbers. Multiply those factors together to get the LCM." },
  { q: "What is the LCM used for in math?", a: "LCM is used to add fractions with different denominators, solve repeating-cycle problems, compare rates, and find common intervals." },
  { q: "What is the difference between LCM and GCF?", a: "LCM is the smallest shared multiple. GCF is the largest shared factor. LCM looks upward at multiples, while GCF looks downward at divisors." },
  { q: "How do you find the LCM of three numbers?", a: "Prime factor all three numbers and use the highest power of each prime appearing in any number, then multiply those prime powers together." },
];

const gcd = (a: number, b: number): number => b === 0 ? Math.abs(a) : gcd(b, a % b);
const lcm2 = (a: number, b: number) => Math.abs(a * b) / gcd(a, b);
const factors = (n: number) => {
  const out: Record<number, number> = {};
  let x = Math.abs(n);
  for (let p = 2; p * p <= x; p++) while (x % p === 0) { out[p] = (out[p] || 0) + 1; x /= p; }
  if (x > 1) out[x] = (out[x] || 0) + 1;
  return out;
};
const factorText = (f: Record<number, number>) => Object.entries(f).map(([p, e]) => e === 1 ? p : `${p}^${e}`).join(" x ") || "1";

export default function LCMCalculator() {
  const [input, setInput] = useState("12, 18, 30");
  const result = useMemo(() => {
    const nums = input.split(/[\s,;]+/).map((n) => Math.abs(Math.trunc(Number(n)))).filter((n) => Number.isFinite(n) && n > 0).slice(0, 10);
    if (nums.length < 2) return null;
    const gcf = nums.reduce((acc, n) => gcd(acc, n));
    const lcm = nums.reduce((acc, n) => lcm2(acc, n));
    const primeMaps = nums.map(factors);
    const merged: Record<number, number> = {};
    primeMaps.forEach((map) => Object.entries(map).forEach(([p, e]) => { merged[Number(p)] = Math.max(merged[Number(p)] || 0, e); }));
    return { nums, gcf, lcm, primeMaps, merged };
  }, [input]);

  return (
    <>
      <SEOHead title="Free LCM Calculator Online - Find Least Common Multiple of Any Numbers Instantly | CalcHive" description="Free online LCM calculator. Find the least common multiple of two or more numbers instantly with step by step prime factorization. 100% free for students, no signup required." canonical="/lcm-calculator" keywords="free LCM calculator, least common multiple calculator free online, LCM of two numbers calculator free, find LCM free, least common multiple finder free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Least Common Multiple Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free LCM calculator to find LCM free for two or more numbers with prime factorization steps.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <label htmlFor="lcm-input" className="text-sm font-semibold text-foreground block mb-2">Numbers, up to 10</label>
          <input id="lcm-input" value={input} onChange={(event) => setInput(event.target.value)} className="w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
          {result ? <motion.div key={input} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }} className="mt-8">
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Least Common Multiple</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-lcm">{result.lcm.toLocaleString()}</p><p className="text-white/70 text-sm mt-1">GCF: {result.gcf.toLocaleString()}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.nums.map((n, i) => `${n} = ${factorText(result.primeMaps[i])}`).join("; ")}. Use highest prime powers: {factorText(result.merged)} = {result.lcm.toLocaleString()}.</p></div>
          </motion.div> : <p className="text-center text-muted-foreground py-6">Enter at least two positive integers.</p>}
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Find the LCM of Any Numbers for Free</h2><p className="text-muted-foreground leading-relaxed">Enter two or more integers and this least common multiple finder free tool calculates the smallest shared multiple instantly.</p><h2 className="text-2xl font-bold text-foreground">How to Calculate LCM Using Prime Factorization</h2><p className="text-muted-foreground leading-relaxed">The calculator breaks each number into prime factors and multiplies the highest power of each prime.</p><h2 className="text-2xl font-bold text-foreground">Free LCM Math Tool for Students</h2><p className="text-muted-foreground leading-relaxed">Use this LCM of two numbers calculator free for fractions, multiples, schedules, and number theory practice.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/lcm-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


